import React from 'react';
import { Input, Select, Button, useDirtyTracking, type OnDirtyChange } from '@linm-soft/common-components';
import type { CustomerDto } from '../../../services/master/models';
import { normalizeCode, normalizeCodeOptional } from '../../../utils/codeField';
import { selectPlaceholderClass } from '../../../utils/selectField';
import { CatalogFormFooter, CatalogFormHistorySlot, SharedCatalogFormActions } from '../../catalog';
import type { SharedCatalogFormIntegrationProps } from '../../catalog';
import styles from '../../../styles/erpPage.module.css';
import { useCustomerForm, type UseCustomerFormOptions } from './useCustomerForm';

export interface CustomerFormProps extends UseCustomerFormOptions {
  testIdPrefix: string;
  /** Resolved company display label — pass `labelFor(companyId ?? sessionCompanyId)` from caller */
  companyName?: string;
  hideCompanyField?: boolean;
  readOnly?: boolean;
  sharedCatalog?: SharedCatalogFormIntegrationProps;
  onCancel: () => void;
  onValidationFailed?: () => void;
  onDirtyChange?: OnDirtyChange;
}

/** Form tạo/sửa đối tượng — dùng chung catalog (`DoiTuongPage`) + search parcel. */
export const CustomerForm: React.FC<CustomerFormProps> = ({
  testIdPrefix,
  editing = null,
  initialName,
  defaultCustomerType,
  initFormName,
  listGroupOptions,
  companyName,
  hideCompanyField = false,
  readOnly = false,
  sharedCatalog,
  onCancel,
  onSaved,
  onValidationFailed,
  onDirtyChange,
}) => {
  const { markDirty, markClean } = useDirtyTracking(onDirtyChange);
  const {
    form,
    setForm,
    errors,
    saving,
    groupOpts,
    clearFieldError,
    applyGroupSelection,
    handleSave,
  } = useCustomerForm({
    editing,
    initialName,
    defaultCustomerType,
    initFormName,
    listGroupOptions,
    onSaved,
    markClean,
  });

  const onSaveClick = async () => {
    const ok = await handleSave();
    if (!ok && onValidationFailed) onValidationFailed();
  };

  return (
    <>
      <div className={styles.formGrid}>
        <div className={styles.masterCodeNameRow}>
          <div className={styles.field} data-testid={`${testIdPrefix}-field-code`}>
            <label className={styles.label}>Mã đối tượng *</label>
            <Input
              value={form.code ?? ''}
              disabled={!!editing}
              error={errors.code}
              className={styles.codeInput}
              onChange={e => {
                markDirty();
                clearFieldError('code');
                setForm(f => ({ ...f, code: normalizeCode(e.target.value) }));
              }}
            />
          </div>
          <div className={styles.field} data-testid={`${testIdPrefix}-field-name`}>
            <label className={styles.label}>Tên đối tượng *</label>
            <Input
              value={form.name ?? ''}
              disabled={readOnly}
              error={errors.name}
              onChange={e => {
                markDirty();
                clearFieldError('name');
                setForm(f => ({ ...f, name: e.target.value }));
              }}
            />
          </div>
        </div>
        <div className={styles.field} data-testid={`${testIdPrefix}-field-customerGroupId`}>
          <label className={styles.label}>Nhóm đối tượng *</label>
          <Select
            value={form.customerGroupId ?? ''}
            placeholder="Chọn nhóm"
            className={selectPlaceholderClass(form.customerGroupId ?? '')}
            error={errors.customerGroupId}
            onChange={e => {
              markDirty();
              clearFieldError('customerGroupId');
              applyGroupSelection(e.target.value);
            }}
            options={groupOpts}
            disabled={readOnly || groupOpts.length === 0}
          />
        </div>
        <div className={styles.field} data-testid={`${testIdPrefix}-field-taxCode`}>
          <label className={styles.label}>Mã số thuế</label>
          <Input
            value={form.taxCode ?? ''}
            disabled={readOnly}
            className={styles.codeInput}
            onChange={e => {
              markDirty();
              setForm(f => ({ ...f, taxCode: normalizeCodeOptional(e.target.value) }));
            }}
          />
        </div>
        <div className={styles.field} data-testid={`${testIdPrefix}-field-address`}>
          <label className={styles.label}>Địa chỉ</label>
          <Input
            value={form.address ?? ''}
            disabled={readOnly}
            onChange={e => {
              markDirty();
              setForm(f => ({ ...f, address: e.target.value }));
            }}
          />
        </div>
        <div className={styles.field} data-testid={`${testIdPrefix}-field-phone`}>
          <label className={styles.label}>Số điện thoại</label>
          <Input
            value={form.phone ?? ''}
            disabled={readOnly}
            onChange={e => {
              markDirty();
              setForm(f => ({ ...f, phone: e.target.value }));
            }}
          />
        </div>
      </div>
      {sharedCatalog && (
        <SharedCatalogFormActions
          testIdPrefix={testIdPrefix}
          row={editing}
          currentValues={{
            name: form.name,
            taxCode: form.taxCode,
            phone: form.phone,
            isActive: form.isActive,
          }}
          {...sharedCatalog}
        />
      )}
      {readOnly ? (
        <div className={styles.modalActions}>
          <Button variant="secondary" onClick={onCancel}>Đóng</Button>
        </div>
      ) : (
        <CatalogFormFooter
          companyName={companyName}
          testIdPrefix={testIdPrefix}
          checked={form.isActive ?? true}
          onActiveChange={c => {
            markDirty();
            setForm(f => ({ ...f, isActive: c }));
          }}
          onCancel={onCancel}
          onSave={() => { void onSaveClick(); }}
          saving={saving}
          saveDisabled={groupOpts.length === 0}
          hideCompanyField={hideCompanyField}
          historySlot={
            <CatalogFormHistorySlot
              testIdPrefix={testIdPrefix}
              catalogKind="customers"
              editing={editing ? { id: editing.customerId, code: editing.code } : null}
            />
          }
        />
      )}
    </>
  );
};

export type { CustomerDto };
