import React, { useEffect, useState } from 'react';
import { Button, Input, Modal, addToast } from '@linm-soft/common-components';
import {
  applyCodeReplaceJob,
  confirmCodeReplace,
  fetchCodeUsageImpact,
  getCodeReplaceJob,
  previewCodeReplace,
  type CodeReplaceJob,
  type CodeReplaceJobLine,
} from '../../services/master/codeReplace';
import styles from '../../styles/erpPage.module.css';

export interface CodeUsageImpactRow {
  tableName: string;
  entityLabel: string;
  estimatedCount: number;
}

export interface CatalogRenameCodeModalProps {
  testIdPrefix: string;
  isOpen: boolean;
  onClose: () => void;
  catalogKind: string;
  oldCode: string;
  oldName?: string;
  /** Preview (default) — draft + approve apply · Confirm — execute ngay */
  renameMode?: 'preview' | 'confirm';
  /** When opening draft job from form banner */
  draftJobId?: string;
  /** Chỉ xem/apply draft — ẩn nhập mã mới */
  viewDraftOnly?: boolean;
  mergeIfExists?: boolean;
  /** Live debounced impact while typing (optional — falls back to usage-impact API) */
  fetchImpact?: (catalogKind: string, code: string, newCode: string) => Promise<CodeUsageImpactRow[]>;
  onCompleted?: () => void;
  /** @deprecated use renameMode + onCompleted */
  onSubmit?: (newCode: string, mergeIfExists: boolean) => Promise<void>;
}

export const CatalogRenameCodeModal: React.FC<CatalogRenameCodeModalProps> = ({
  testIdPrefix,
  isOpen,
  onClose,
  catalogKind,
  oldCode,
  oldName,
  renameMode = 'preview',
  draftJobId,
  viewDraftOnly = false,
  mergeIfExists: mergeIfExistsProp = false,
  fetchImpact,
  onCompleted,
  onSubmit,
}) => {
  const [newCode, setNewCode] = useState('');
  const [impact, setImpact] = useState<CodeUsageImpactRow[]>([]);
  const [loadingImpact, setLoadingImpact] = useState(false);
  const [submitting, setSubmitting] = useState(false);
  const [mergeIfExists, setMergeIfExists] = useState(false);
  const [draftJob, setDraftJob] = useState<CodeReplaceJob | null>(null);
  const [step, setStep] = useState<'input' | 'preview'>('input');

  useEffect(() => {
    if (!isOpen) return;
    setNewCode('');
    setImpact([]);
    setMergeIfExists(mergeIfExistsProp);
    setDraftJob(null);
    setStep(viewDraftOnly && draftJobId ? 'preview' : 'input');
  }, [isOpen, oldCode, viewDraftOnly, draftJobId, mergeIfExistsProp]);

  useEffect(() => {
    if (!isOpen || !viewDraftOnly || !draftJobId) return;
    let cancelled = false;
    setSubmitting(true);
    getCodeReplaceJob(draftJobId)
      .then(job => { if (!cancelled) { setDraftJob(job); setNewCode(job.newCode); } })
      .catch(err => {
        if (!cancelled) {
          addToast({
            message: err instanceof Error ? err.message : 'Không tải được preview',
            type: 'error',
          });
        }
      })
      .finally(() => { if (!cancelled) setSubmitting(false); });
    return () => { cancelled = true; };
  }, [isOpen, viewDraftOnly, draftJobId]);

  useEffect(() => {
    if (!isOpen || viewDraftOnly || !newCode.trim()) {
      setImpact([]);
      return;
    }
    const loadImpact = fetchImpact ?? ((kind, old, neu) =>
      fetchCodeUsageImpact(kind, old, neu));
    let cancelled = false;
    setLoadingImpact(true);
    const t = setTimeout(() => {
      loadImpact(catalogKind, oldCode, newCode.trim().toUpperCase())
        .then(rows => { if (!cancelled) setImpact(rows); })
        .catch(() => { if (!cancelled) setImpact([]); })
        .finally(() => { if (!cancelled) setLoadingImpact(false); });
    }, 300);
    return () => { cancelled = true; clearTimeout(t); };
  }, [isOpen, viewDraftOnly, catalogKind, oldCode, newCode, fetchImpact]);

  const totalAffected = draftJob
    ? draftJob.totalAffectedCount
    : impact.reduce((s, r) => s + r.estimatedCount, 0);

  const previewLines: CodeReplaceJobLine[] = draftJob?.lines ?? [];

  const validateNewCode = (): string | null => {
    const code = newCode.trim().toUpperCase();
    if (!code) return 'Nhập mã mới';
    if (code === oldCode.toUpperCase()) return 'Mã mới phải khác mã hiện tại';
    return null;
  };

  const runLegacySubmit = async (code: string) => {
    if (onSubmit) {
      await onSubmit(code, mergeIfExists);
      return;
    }
    throw new Error('Chưa cấu hình API đổi mã');
  };

  const handlePreview = async () => {
    const err = validateNewCode();
    if (err) {
      addToast({ message: err, type: 'error' });
      return;
    }
    setSubmitting(true);
    try {
      const job = await previewCodeReplace({
        catalogKind,
        oldCode,
        newCode: newCode.trim().toUpperCase(),
        mergeIfExists,
      });
      setDraftJob(job);
      setStep('preview');
      addToast({ message: 'Đã tạo preview — xem bảng ảnh hưởng và áp dụng', type: 'success' });
    } catch (err: unknown) {
      addToast({
        message: err instanceof Error ? err.message : 'Preview thất bại',
        type: 'error',
      });
    } finally {
      setSubmitting(false);
    }
  };

  const handleApply = async () => {
    const jobId = draftJob?.id ?? draftJobId;
    if (!jobId) {
      addToast({ message: 'Chưa có job preview', type: 'error' });
      return;
    }
    setSubmitting(true);
    try {
      await applyCodeReplaceJob(jobId);
      addToast({ message: 'Đổi mã thành công', type: 'success' });
      onCompleted?.();
      onClose();
    } catch (err: unknown) {
      addToast({
        message: err instanceof Error ? err.message : 'Áp dụng đổi mã thất bại',
        type: 'error',
      });
    } finally {
      setSubmitting(false);
    }
  };

  const handleConfirm = async () => {
    const err = validateNewCode();
    if (err) {
      addToast({ message: err, type: 'error' });
      return;
    }
    setSubmitting(true);
    try {
      if (onSubmit && !renameMode) {
        await runLegacySubmit(newCode.trim().toUpperCase());
      } else {
        await confirmCodeReplace({
          catalogKind,
          oldCode,
          newCode: newCode.trim().toUpperCase(),
          mergeIfExists,
        });
        addToast({ message: 'Đổi mã thành công', type: 'success' });
      }
      onCompleted?.();
      onClose();
    } catch (err: unknown) {
      addToast({
        message: err instanceof Error ? err.message : 'Đổi mã thất bại',
        type: 'error',
      });
    } finally {
      setSubmitting(false);
    }
  };

  const primaryAction = () => {
    if (viewDraftOnly || step === 'preview') return void handleApply();
    if (renameMode === 'confirm') return void handleConfirm();
    return void handlePreview();
  };

  const primaryLabel = () => {
    if (submitting) return 'Đang xử lý…';
    if (viewDraftOnly || step === 'preview') return 'Áp dụng đổi mã';
    if (renameMode === 'confirm') return 'Xác nhận đổi mã';
    return 'Xem preview';
  };

  const showInput = !viewDraftOnly && step === 'input';
  const showPreviewTable = step === 'preview' || viewDraftOnly;

  return (
    <Modal
      isOpen={isOpen}
      onClose={onClose}
      title="Đổi mã danh mục"
      size="lg"
      data-testid={`${testIdPrefix}-rename-code-modal`}
    >
      <div className={styles.catalogModalBody}>
        <div className={styles.catalogWarningBanner}>
          <i className="fas fa-exclamation-triangle" />
          Thao tác propagate toàn hệ thống. BE rollback toàn bộ nếu một bước lỗi.
        </div>
        <div className={styles.field}>
          <label className={styles.label}>Mã hiện tại</label>
          <Input value={oldCode} disabled />
          {oldName ? <span className={styles.sharedCatalogHint}>{oldName}</span> : null}
        </div>
        {showInput && (
          <div className={styles.field}>
            <Input
              label="Mã mới *"
              value={newCode}
              className={styles.codeInput}
              data-testid={`${testIdPrefix}-rename-new-code`}
              onChange={e => setNewCode(e.target.value.toUpperCase())}
            />
          </div>
        )}
        {showPreviewTable && previewLines.length > 0 && (
          <div className={styles.catalogImpactBlock}>
            <h4 className={styles.catalogImpactTitle}>Preview thay thế</h4>
            <p>Tổng cộng <strong>{totalAffected}</strong> bản ghi · {draftJob?.newCode ?? newCode}</p>
            <table className={styles.catalogImpactTable}>
              <thead>
                <tr>
                  <th>Phase</th>
                  <th>Bảng</th>
                  <th>Cột</th>
                  <th>Mô tả</th>
                  <th>Số lượng</th>
                </tr>
              </thead>
              <tbody>
                {previewLines.map(line => (
                  <tr key={`${line.tableName}-${line.columnName}-${line.sortOrder}`}>
                    <td>{line.phase}</td>
                    <td><code>{line.tableName}</code></td>
                    <td><code>{line.columnName}</code></td>
                    <td>{line.entityLabel}</td>
                    <td>{line.estimatedCount}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
        {showInput && newCode.trim() && !showPreviewTable && (
          <div className={styles.catalogImpactBlock}>
            <h4 className={styles.catalogImpactTitle}>Ảnh hưởng ước tính</h4>
            {loadingImpact ? (
              <p className={styles.sharedCatalogHint}>Đang tải…</p>
            ) : impact.length === 0 ? (
              <p className={styles.sharedCatalogHint}>Chưa có dữ liệu tham chiếu.</p>
            ) : (
              <>
                <p>Tổng cộng khoảng <strong>{totalAffected}</strong> bản ghi.</p>
                <table className={styles.catalogImpactTable}>
                  <thead>
                    <tr>
                      <th>Bảng</th>
                      <th>Mô tả</th>
                      <th>Số lượng</th>
                    </tr>
                  </thead>
                  <tbody>
                    {impact.map(row => (
                      <tr key={row.tableName}>
                        <td><code>{row.tableName}</code></td>
                        <td>{row.entityLabel}</td>
                        <td>{row.estimatedCount}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </>
            )}
          </div>
        )}
        {showInput && (
          <label className={styles.catalogMergePick}>
            <input
              type="checkbox"
              checked={mergeIfExists}
              onChange={e => setMergeIfExists(e.target.checked)}
            />
            Gộp nếu mã đích đã tồn tại
          </label>
        )}
      </div>
      <div className={styles.modalFooterBar}>
        <Button variant="secondary" onClick={onClose} disabled={submitting}>Hủy</Button>
        {step === 'preview' && !viewDraftOnly && renameMode === 'preview' ? (
          <Button variant="secondary" disabled={submitting} onClick={() => setStep('input')}>
            Sửa mã mới
          </Button>
        ) : null}
        <Button
          variant="primary"
          disabled={submitting || (showInput && !newCode.trim())}
          data-testid={
            viewDraftOnly || step === 'preview'
              ? `${testIdPrefix}-rename-apply-btn`
              : `${testIdPrefix}-rename-submit`
          }
          onClick={primaryAction}
        >
          {primaryLabel()}
        </Button>
      </div>
    </Modal>
  );
};
